query:
SELECT * FROM peppr_stay_tokens LIMIT 5;
SELECT id, qr_code_id, status FROM peppr_qr_codes WHERE status != 'active' LIMIT 3;
SELECT q.id, q.qr_code_id, q.property_id, q.room_id, st.token FROM peppr_qr_codes q JOIN peppr_stay_tokens st ON st.room_id = q.room_id WHERE q.access_type = 'restricted' AND q.status = 'active' LIMIT 1;

